use std::io;
use std::str::FromStr;
use std::io::prelude::*;

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

fn main() {
    let n: u64 = get_line().trim().parse().unwrap();

    let get_beautiful = |i: u64| -> u64 {
        ((1 << i) - 1) << (i - 1)
    };

    let ans = (1..).map(|i| get_beautiful(i)).take_while(|&i| i <= n)
        .filter(|&i| n % i == 0).max().unwrap();

    println!("{}", ans);
}

